import { MarkupNode } from '../model'
import { extractReferences } from '../reference'

describe('extractReferences', () => {
  it('extract no references', () => {
    const node = {
      type: 'paragraph',
      content: [
        {
          type: 'text',
          text: 'Hello, world!'
        }
      ]
    }

    const references = extractReferences(node as MarkupNode)
    expect(references).toHaveLength(0)
  })

  it('extracts references', () => {
    const node = {
      type: 'paragraph',
      content: [
        {
          type: 'text',
          text: 'Hello, world!'
        },
        {
          type: 'reference',
          attrs: {
            id: '1',
            objectclass: 'core:class:'
          }
        }
      ]
    }

    const references = extractReferences(node as MarkupNode)
    expect(references).toHaveLength(0)
  })
})
